/** Return today's On This Day entry, or null if none exists for this date. */
export function getTodaysEntry(): OnThisDayEntry | null {
  const now = new Date();
  const m = now.getMonth() + 1;
  const d = now.getDate();
  return ON_THIS_DAY.find(e => e.month === m && e.day === d) ?? null;
}
